import React from "react";
import { Text, View, StyleSheet } from "react-native";

export default function Settings() {
  return (
    <View style={styles.flexCenter}>
      <Text>Settings</Text>
    </View>
  );
}

const styles = StyleSheet.create({
  flexCenter: {
    alignItems: "center",
    justifyContent: "center",
    flex: 1,
  },
});
